"""Translation strings for i18n support."""

TRANSLATIONS = {
    "en": {"greet": "Hello, {name}!", "farewell": "Goodbye, {name}!"},
    "es": {"greet": "Hola, {name}!", "farewell": "Adiós, {name}!"},
    "fr": {"greet": "Bonjour, {name}!", "farewell": "Au revoir, {name}!"}
}


def get_translation(key, locale="en"):
    translations = TRANSLATIONS.get(locale, TRANSLATIONS["en"])
    return translations.get(key, TRANSLATIONS["en"][key])

"""Greeting module with i18n support."""
from src.translations import get_translation


def greet(name, locale="en"):
    template = get_translation("greet", locale)
    return template.format(name=name)


def farewell(name, locale="en"):
    template = get_translation("farewell", locale)
    return template.format(name=name)

"""Main entry point with i18n demo."""
from src.greeting import greet


def main():
    for locale in ["en", "es", "fr"]:
        print(greet("World", locale=locale))


if __name__ == "__main__":
    main()

"""Tests for greeting module with i18n."""
from src.greeting import greet, farewell


def test_greet_english():
    assert greet("Alice") == "Hello, Alice!"


def test_greet_spanish():
    assert greet("Alice", locale="es") == "Hola, Alice!"


def test_greet_french():
    assert greet("Alice", locale="fr") == "Bonjour, Alice!"


def test_farewell_english():
    assert farewell("Alice") == "Goodbye, Alice!"
